-- ============================================
-- Legislacao full-site: expedito-netto / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/178953
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = expedito-netto-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 46
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=178953, tipo Deputado(a), ordemAssinatura=1.
-- 54 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'expedito-netto';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'expedito-netto: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao expedito-netto: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2250935', '2246429', '2341068', '2311593', '2341066', '2331359', '2309904', '2296892', '2331210', '2305054', '2339918', '2311592', '2297859', '2311590', '2297853', '2260445', '2259399', '2300717', '2296328', '2298275', '2296891', '2259405', '2259396', '2246432', '2238421', '2279163', '2259401', '2259394', '2251621', '2246430', '2276071', '2260440', '2259397', '2246433', '2246427', '2228839', '2279571', '2259404', '2259395', '2256559', '2246431', '2331374', '2258982', '2300715', '2298274', '2339977');
  IF target_present <> 46 THEN
    RAISE EXCEPTION 'Pre-condicao expedito-netto: esperadas 46 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2250935', '2246429', '2341068', '2311593', '2341066', '2331359', '2309904', '2296892', '2331210', '2305054', '2339918', '2311592', '2297859', '2311590', '2297853', '2260445', '2259399', '2300717', '2296328', '2298275', '2296891', '2259405', '2259396', '2246432', '2238421', '2279163', '2259401', '2259394', '2251621', '2246430', '2276071', '2260440', '2259397', '2246433', '2246427', '2228839', '2279571', '2259404', '2259395', '2256559', '2246431', '2331374', '2258982', '2300715', '2298274', '2339977')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'expedito-netto-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao expedito-netto: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao expedito-netto: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

